package com.monthlyexpo.repository; import com.monthlyexpo.entity.Customer; import org.springframework.data.jpa.repository.JpaRepository; import java.util.List; public interface CustomerRepository extends JpaRepository<Customer,Long>{ List<Customer> findByNameContainingIgnoreCase(String name); List<Customer> findByVillageNameContainingIgnoreCase(String villageName); long countByVillageNameIgnoreCase(String villageName); }
